const main = ":root{--bg:#0b1020;--panel:#111a33;--text:#e6e8f0;--muted:#a9afc3;--brand:#6d5efc;--danger:#ff4d4d;--success:#2ecc71;--border:hsla(0,0%,100%,.12)}*{box-sizing:border-box}body,html{height:100%}body{background:radial-gradient(1200px 600px at 20% 10%,rgba(109,94,252,.35),transparent 40%),radial-gradient(900px 500px at 90% 20%,rgba(46,204,113,.2),transparent 50%),var(--bg);color:var(--text);font-family:ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,Apple Color Emoji,Segoe UI Emoji;margin:0}a{color:inherit;text-decoration:none}.container{margin:0 auto;max-width:1100px;padding:20px}.card{-webkit-backdrop-filter:blur(10px);backdrop-filter:blur(10px);background:linear-gradient(180deg,#ffffff0f,#ffffff08);border:1px solid var(--border);border-radius:14px;padding:16px}.grid{display:grid;gap:16px}.btn{-webkit-appearance:none;-moz-appearance:none;appearance:none;background:#ffffff0f;border:1px solid var(--border);border-radius:10px;color:var(--text);cursor:pointer;padding:10px 12px}.btn.primary{background:var(--brand);border-color:#6d5efc80}.btn.danger{background:#ff4d4d2e;border-color:#ff4d4d66}.btn:disabled{cursor:not-allowed;opacity:.55}.input,select{background:#00000040;border:1px solid var(--border);border-radius:10px;color:var(--text);padding:10px 12px;width:100%}.label{margin-bottom:6px}.badge,.help,.label{color:var(--muted);font-size:12px}.badge{align-items:center;border:1px solid var(--border);border-radius:999px;display:inline-flex;gap:6px;padding:4px 10px}.topbar{justify-content:space-between}.nav,.topbar{align-items:center;display:flex;gap:10px}.nav{flex-wrap:wrap}.table{border-collapse:collapse;width:100%}.table td,.table th{border-bottom:1px solid var(--border);padding:10px;text-align:left}.kpi{display:flex;flex-direction:column;gap:6px}.kpi .v{font-size:22px;font-weight:700}.row{display:flex;flex-wrap:wrap;gap:12px}.row>*{flex:1 1 240px}";
